import{_ as t,c as a,o as e,a4 as d}from"./chunks/framework.CzjLcc5X.js";const q=JSON.parse('{"title":"日本 -> 北海道 -> 交通 -> JR北海道鐵路周遊券","description":"","frontmatter":{},"headers":[],"relativePath":"日本/北海道/交通/JR北海道鐵路周遊券.md","filePath":"日本/北海道/交通/JR北海道鐵路周遊券.md","lastUpdated":1690558668000}'),r={name:"日本/北海道/交通/JR北海道鐵路周遊券.md"},h=d('<h1 id="jr北海道鐵路周遊券" tabindex="-1">JR北海道鐵路周遊券 <a class="header-anchor" href="#jr北海道鐵路周遊券" aria-label="Permalink to &quot;JR北海道鐵路周遊券&quot;">​</a></h1><p>周遊寬廣的北海道，盡享北海道旅行的樂趣，可選擇5天、7天或10天(2023年10月1日起上市)版本並在有效期間內可自由乘坐JR北海道的列車。</p><h2 id="價格・種類" tabindex="-1">價格・種類 <a class="header-anchor" href="#價格・種類" aria-label="Permalink to &quot;價格・種類&quot;">​</a></h2><h3 id="至2023年9月30日為止購票" tabindex="-1">至2023年9月30日為止購票 <a class="header-anchor" href="#至2023年9月30日為止購票" aria-label="Permalink to &quot;至2023年9月30日為止購票&quot;">​</a></h3><h4 id="_5日用" tabindex="-1">5日用 <a class="header-anchor" href="#_5日用" aria-label="Permalink to &quot;5日用&quot;">​</a></h4><table><thead><tr><th></th><th>成人</th><th>兒童(6-11歲)</th></tr></thead><tbody><tr><td>赴日前購票</td><td>19,000日圓</td><td>9,500日圓</td></tr><tr><td>日本國內購票</td><td>20,000日圓</td><td>10,000日圓</td></tr></tbody></table><h4 id="_7日用" tabindex="-1">7日用 <a class="header-anchor" href="#_7日用" aria-label="Permalink to &quot;7日用&quot;">​</a></h4><table><thead><tr><th></th><th>成人</th><th>兒童(6-11歲)</th></tr></thead><tbody><tr><td>赴日前購票</td><td>25,000日圓</td><td>12,500日圓</td></tr><tr><td>日本國內購票</td><td>26,000日圓</td><td>13,000日圓</td></tr></tbody></table><h3 id="_2023年10月1日起購票" tabindex="-1">2023年10月1日起購票 <a class="header-anchor" href="#_2023年10月1日起購票" aria-label="Permalink to &quot;2023年10月1日起購票&quot;">​</a></h3><h4 id="_5日用-1" tabindex="-1">5日用 <a class="header-anchor" href="#_5日用-1" aria-label="Permalink to &quot;5日用&quot;">​</a></h4><table><thead><tr><th></th><th>成人</th><th>兒童(6-11歲)</th></tr></thead><tbody><tr><td>赴日前購票</td><td>20,000日圓</td><td>10,000日圓</td></tr><tr><td>日本國內購票</td><td>21,000日圓</td><td>11,000日圓</td></tr></tbody></table><h4 id="_7日用-1" tabindex="-1">7日用 <a class="header-anchor" href="#_7日用-1" aria-label="Permalink to &quot;7日用&quot;">​</a></h4><table><thead><tr><th></th><th>成人</th><th>兒童(6-11歲)</th></tr></thead><tbody><tr><td>赴日前購票</td><td>26,000日圓</td><td>13,000日圓</td></tr><tr><td>日本國內購票</td><td>27,000日圓</td><td>13,500日圓</td></tr></tbody></table><h4 id="_10日用" tabindex="-1">10日用 <a class="header-anchor" href="#_10日用" aria-label="Permalink to &quot;10日用&quot;">​</a></h4><table><thead><tr><th></th><th>成人</th><th>兒童(6-11歲)</th></tr></thead><tbody><tr><td>赴日前購票</td><td>32,000日圓</td><td>16,000日圓</td></tr><tr><td>日本國內購票</td><td>33,000日圓</td><td>16,500日圓</td></tr></tbody></table><h2 id="購票資格" tabindex="-1">購票資格 <a class="header-anchor" href="#購票資格" aria-label="Permalink to &quot;購票資格&quot;">​</a></h2><p>只限持「短期滯在」資格入境，持非日本國護照的訪日外籍旅客才可使用。</p><h2 id="有效期間" tabindex="-1">有效期間 <a class="header-anchor" href="#有效期間" aria-label="Permalink to &quot;有效期間&quot;">​</a></h2><ul><li>9月30日為止購票（現行價格）：5天或7天 ※從旅客自行指定的使用日期生效，可連續使用5天或7天。</li><li>10月1日起購票（新價格）：：5天、7天或10天 ※從旅客自行指定的使用日期生效，可連續使用5天、7天或10天。</li></ul><h2 id="有效乘車區域・列車" tabindex="-1">有效乘車區域・列車 <a class="header-anchor" href="#有效乘車區域・列車" aria-label="Permalink to &quot;有效乘車區域・列車&quot;">​</a></h2><p>有效期間內可自由乘坐JR北海道線（不含北海道新幹線）所有的列車。</p><h2 id="相關連結" tabindex="-1">相關連結 <a class="header-anchor" href="#相關連結" aria-label="Permalink to &quot;相關連結&quot;">​</a></h2><ul><li><a href="https://www.jrhokkaido.co.jp/global/chinese/ticket/railpass/index.html#hrp" target="_blank" rel="noreferrer">北海道鐵路旅客公司</a></li></ul>',23),o=[h];function l(i,n,s,b,c,_){return e(),a("div",null,o)}const f=t(r,[["render",l]]);export{q as __pageData,f as default};
